let cur = 0;
const book = document.getElementById('book');
const dotsEl = document.getElementById('dots');
const pnEl = document.getElementById('pn');
const prevBtn = document.getElementById('prev');
const nextBtn = document.getElementById('next');

// 初始化页面
pages.forEach((html, i) => {
  const div = document.createElement('div');
  div.className = `pg p${i}` + (i === 0 ? ' on' : '');
  div.innerHTML = html;
  book.appendChild(div);

  const dot = document.createElement('div');
  dot.className = 'dot' + (i === 0 ? ' on' : '');
  dot.onclick = () => jump(i);
  dotsEl.appendChild(dot);
});

function jump(n) {
  if (n < 0 || n >= pages.length || n === cur) return;
  const allPg = book.querySelectorAll('.pg');
  const allDot = dotsEl.querySelectorAll('.dot');
  allPg[cur].classList.remove('on');
  allDot[cur].classList.remove('on');
  cur = n;
  allPg[cur].classList.add('on');
  allDot[cur].classList.add('on');
  allPg[cur].scrollTop = 0;
  update();
}

function go(d) { jump(cur + d); }

function update() {
  pnEl.textContent = (cur + 1) + ' / ' + pages.length;
  prevBtn.disabled = cur === 0;
  nextBtn.disabled = cur === pages.length - 1;
}

update();

// 触摸滑动支持
let tx = 0;
book.addEventListener('touchstart', e => { tx = e.touches[0].clientX; }, {passive:true});
book.addEventListener('touchend', e => {
  const dx = e.changedTouches[0].clientX - tx;
  if (Math.abs(dx) > 50) go(dx < 0 ? 1 : -1);
}, {passive:true});

// 键盘支持
document.addEventListener('keydown', e => {
  if (e.key === 'ArrowLeft' || e.key === 'ArrowUp') go(-1);
  if (e.key === 'ArrowRight' || e.key === 'ArrowDown' || e.key === ' ') go(1);
});
</script>
</body>
</html>

